import { ComplexConstraint } from './complex-constraint';
import { DeletionConstraint } from './deletion-constraint';
import { SchemaConstraintRestDto } from './schema-constraint-rest-dto';
import { SchemaDefinitionRestDtoEnums } from './schema-definition-rest-dto-enums';
import { SchemaDefinitionRestDtoMetadata } from './schema-definition-rest-dto-metadata';
import { SchemaDefinitionRestDtoProperties } from './schema-definition-rest-dto-properties';
import { SchemaDefinitionRestDtoTableColumns } from './schema-definition-rest-dto-table-columns';
import { SchemaDefinitionRestDtoTypes } from './schema-definition-rest-dto-types';
import { UiCustomization } from './ui-customization';
export interface SchemaDefinitionRestDto {
    /**
     * A list of scopes where the schema can be used.
     */
    allowedScopes: string[];
    /**
     * A list of constrains limiting the values to be accepted by the schema.
     */
    constraints?: ComplexConstraint[];
    /**
     * Constraints limiting the values to be deleted.
     */
    deletionConstraints?: DeletionConstraint[];
    /**
     * A short description of the schema.
     */
    description: string;
    /**
     * The display name of the schema.
     */
    displayName: string;
    /**
     * An extended description of the schema and/or links to documentation.
     */
    documentation?: string;
    /**
     * The version of the data format.
     */
    dynatrace: string;
    /**
     * A list of definitions of enum properties.
     */
    enums: SchemaDefinitionRestDtoEnums;
    /**
     * Name of the key property in this schema.
     */
    keyProperty?: string;
    /**
     * The maturity of the schema.
     * Possible values:
     * - PREVIEW: Preview features are not generally available, but might be available in specific environments as part of early-access programs. These are the most likely to change in incompatible ways.
     * - EARLY_ADOPTER: Features marked "early adopter" are available in all environments, but are not mature enough to warrant the "general availability" designation. We don't expect incompatible changes for these, but please be aware, that these are not fully stable yet and incompatible changes may be necessary in rare cases.
     * - GENERAL_AVAILABILITY: Features marked "general availability" are the most stable. While the schemas will still evolve over time, care will be taken to only do so in a backward-compatible manner.
     *
     * In any case, automations should make use of the `schemaVersion` field when writing settings objects.
     */
    maturity?: 'EARLY_ADOPTER' | 'GENERAL_AVAILABILITY' | 'PREVIEW';
    /**
     * The maximum amount of objects per scope.
     *
     * Only applicable when **multiObject** is set to `true`.
     */
    maxObjects: number;
    /**
     * Metadata of the setting.
     */
    metadata?: SchemaDefinitionRestDtoMetadata;
    /**
     * Multiple (`true`) objects per scope are permitted or a single (`false`) object per scope is permitted.
     */
    multiObject: boolean;
    /**
     * If `true` the order of objects has semantic significance.
     *
     * Only applicable when **multiObject** is set to `true`.
     */
    ordered?: boolean;
    /**
     * A list of schema's properties.
     */
    properties: SchemaDefinitionRestDtoProperties;
    /**
     * Constraints limiting the values as a whole to be accepted in this configuration element.
     */
    schemaConstraints?: SchemaConstraintRestDto[];
    /**
     * Names of the groups, which the schema belongs to.
     */
    schemaGroups?: string[];
    /**
     * The ID of the schema.
     */
    schemaId: string;
    /**
     * Table column definitions for use in the ui.
     */
    tableColumns?: SchemaDefinitionRestDtoTableColumns;
    /**
     * A list of definitions of types.
     *
     *  A type is a complex property that contains its own set of subproperties.
     */
    types: SchemaDefinitionRestDtoTypes;
    /**
     * Customization for UI elements
     */
    uiCustomization?: UiCustomization;
    /**
     * The version of the schema.
     */
    version: string;
}
